--
-- Table structure for table `post`
--

DROP TABLE IF EXISTS `post`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `post` (
  `id` int NOT NULL AUTO_INCREMENT,
  `nodeId` int NOT NULL,
  `creator` int NOT NULL,
  `type` tinyint NOT NULL,
  `content` text NOT NULL,
  `once` int NOT NULL,
  `twice` int NOT NULL,
  `helpful` int NOT NULL,
  `commentCount` int NOT NULL DEFAULT '0',
  `state` tinyint NOT NULL DEFAULT '0',
  `score` double NOT NULL DEFAULT '0' COMMENT '计算出的排序分数',
  `score_calculated_at` timestamp NOT NULL DEFAULT CURRENT_TIMESTAMP COMMENT '分数计算时间',
  `ctime` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP,
  `utime` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP,
  `view_count` int DEFAULT '0' COMMENT '总阅读量',
  PRIMARY KEY (`id`),
  KEY `idx_score` (`score` DESC,`id` DESC),
  KEY `idx_post_node_score` (`nodeId`,`score` DESC,`id` DESC)
) ENGINE=InnoDB AUTO_INCREMENT=186 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci;
/*!40101 SET character_set_client = @saved_cs_client */;

