INSERT INTO `post` VALUES (32,1,84,1,'26,27',0,0,1,0,2,0,'2025-08-14 11:42:19','2024-11-05 22:37:15','2025-06-27 01:45:29',0),(33,1,84,1,'28,29,30,31',0,0,1,2,1,0,'2025-08-14 11:42:19','2024-11-06 19:52:41','2025-06-27 01:45:29',0),(34,29,84,1,'32,33',1,0,0,0,1,0,'2025-08-26 14:10:20','2024-11-22 09:49:03','2025-06-27 01:45:29',0),(35,28,84,1,'34,35,36,37,38',2,0,1,2,1,0,'2025-08-14 11:42:19','2024-11-27 16:17:34','2025-06-27 01:45:29',0),(36,28,84,1,'39,40',1,0,1,0,1,0,'2025-08-14 11:42:19','2024-11-27 23:09:16','2025-06-27 01:45:29',0),(37,26,84,1,'41,42,43',0,0,0,0,1,0,'2025-08-14 11:42:19','2024-11-28 00:34:22','2025-06-27 01:45:29',0),(38,34,84,1,'44,45',1,0,0,0,1,0,'2025-08-14 11:42:19','2024-11-28 00:49:19','2025-06-27 01:45:29',0),(39,28,84,2,'近日，四川成都，小孩哥骑自行车出门遇车子故障，孩子小脑袋瓜一转推到附近消防站求助。@成都消防 蓝朋友立马拿出工具，化身“修理工”，一番调试后帮娃将车子修好。小孩哥一句“谢谢消防员叔叔”把蓝朋友整无奈啦~ps:下次再喊叔不帮你了昂~网友：永远可以相信蓝朋友~',2,0,0,0,1,0,'2025-08-14 11:42:19','2024-12-18 11:17:10','2025-06-27 01:45:29',0),(40,28,84,2,'骨子里有股狠劲儿，形容不上来，但总给我这种感觉，这么说吧，这种感觉四川人也有点儿，但是四川人只是脾气上火爆了点儿，湖南人那种感觉像是什么事儿都做得出来一样……\r\n\r\n再说个女生的样本，信不信随你，在西藏拉萨的时候（不是旅游，我是工作），认识的一个长沙女生，长得让人看起来挺舒服，圆咕隆咚的脸，很白，五官还挺立体的，当时我知道她有对象，她也知道我知道她有对象，但是她对象不在拉萨，我也承认我当时确实没安什么好心，总是暗示一样的挑逗她，有一次她和她另一个朋友（四川绵阳人，女生），一起吃饭，她喝了几杯就在那里嗷嗷大哭（就喝了3杯左右，根本没怎么醉），说她对象怎么怎么渣了，对她不好了，然后就倒在那里我还给她扶起来，然后这个女生就开始“动手动脚了”（自己想），那个四川女生就开始说，哎呀小成，你看她都这样了，今晚你照顾她得了，一会儿我开车给你送纳金路（拉萨的一个街道）那里，然后就去了，去了之后，那个酒店前台看她醉了（没醉，在那里装醉，还动手动动脚的，一直装到酒店里），不给开房间，怕出事儿（藏地这种治安事情管的特别严），直接打电话给派出所了，阿Sir来了以后，扯了会儿皮，跟咱们说，今晚必须那个女生（那个四川女生）也要在这里才可以，并且告诉前台，明早查房要去看看，她在不在。后来还是开了，进屋以后那个湖南女生立刻酒醒酒了，也不装醉了，到第二天，来查完房以后咱们才走，当然了，那天晚上也没发生什么，但是，没过多久就发生了',5,0,0,0,1,0,'2025-08-14 11:42:19','2024-12-23 23:33:09','2025-06-27 01:45:29',0),(41,28,84,2,'钱家有个不争气的后学晚辈叫钱雁秋，他20出头写了燕双鹰系列，30出头开始写神探狄仁杰系列，西游记后传是他随手的创作，这在钱氏一门就是个不拔尖的后辈，作为这个大家族的第一人，钱学森水准恐怕常人连评价角度都找不好。有老哥私信问钱家内部的关系，我也说不太好只能简单说一下，大概分杭州钱氏和无锡钱氏两大支脉都是吴越王钱镠的后代可以统称吴越钱氏，这个家族近代出了很多了不得的人物，比如钱穆、钱复、钱钟书、钱学森、钱玄同、钱三强、钱伟长，因为我根本没能力正面评价钱老，所以只能简单说下他的家族，钱老能在这种大家族里作为代表，也算是侧面证明了他的不凡，还有钱家不是所谓的门阀他们家族为新中国做了很杰出的贡献。',1,0,0,0,1,0,'2025-08-14 11:42:19','2024-12-26 19:38:38','2025-06-27 01:45:29',0),(42,28,84,2,'孙某是大连某汽车销售服务有限公司职工，公司上下班时间为8:00——17:00。2020年5月23日7时25分，孙某骑自行车上班途中发生交通事故，经抢救无效死亡。孙某负此次事故同等责任。公司认为，孙某平时从家骑自行车到单位上班的路线是：穿行西郊工业园区兴工大街，不经过瓦交线，直接从公司西门进入，兴工大街平坦、车少，易于骑行，是上下班最短距离的合理路线。而孙某事故发生地是钻石街，该街车流量大，有一段长距离的坡路，只适合推行，不适合骑行，综合考虑骑行的安全性和困难性，该路线不应当认定为上下班的合理路线。\r\n',2,0,0,0,1,0,'2025-08-14 11:42:19','2024-12-26 19:39:28','2025-06-27 01:45:29',0),(43,28,84,2,'作者：海阔美人鱼\r\n链接：https://zhuanlan.zhihu.com/p/14850681951\r\n来源：知乎\r\n著作权归作者所有。商业转载请联系作者获得授权，非商业转载请注明出处。\r\n\r\n处理结果人力资源和社会保障局认为孙某受到的事故伤害符合《工伤保险条例》第十四条第六项之规定，认定孙某为工伤。大连某汽车销售服务有限公司不服，提起诉讼，法院维持了工伤认定决定法律依据《工伤保险条例》第十四条：“职工有下列情形之一的，应当认定为工伤：……（六）在上下班途中，受到非本人主要责任的交通事故或者城市轨道交通、客运轮渡、火车事故伤害的……”《最高人民法院关于审理工伤保险行政案件若干问题的规定》第六条：“对社会保险行政部门认定下列情形为‘上下班途中’的，人民法院应予支持：（一）在合理时间内往返于工作地与住所地、经常居住地、单位宿舍的合理路线的上下班途中……”法律分析职工为上下班而往返于住所和公司之间的路线，不能机械地理解为从公司到职工住所之间的最近路径，合理的上下班路线并非固定的、唯一的最短、最佳路线，对此要作出全面、正确的理解，职工为上班而往返住处和工作单位间的合理路径可以视为合理的上下班路线。根据日常社会生活的实际情况，职工为上下班而往返于住处和工作单位之间的合理路径可能有多种选择。只要在职工为了上班或者下班，在合理时间内往返于住处和工作单位之间的合理路径之中，属于“上下班途中”。本案中，根据导航路线来看，孙某交通事故发生地点在公司正门附近，事故发生地点所在路线虽非上班最佳路线，但也属于上下班的合理路线之一，可以认定交通事故发生在上下班途中，故应予认定为工伤。',1,0,0,0,1,0,'2025-08-14 11:42:19','2024-12-26 19:39:59','2025-06-27 01:45:29',0),(44,28,84,2,'更新：懂王真是霸气冲天，今天已经开始挑选加拿大总督了。而且在12月26日的圣诞祝词里，再次声明需要把加拿大变成美国第51个州，以及美国拿下格陵兰岛。此外，他还解释了为什么美国需要拿下巴拿马运河。原来在他看来，中国非法经营巴拿马运河，导致美国需要花费大量的钱来修复运河，却又没有发言权。\r\n\r\n作者：君山银针\r\n链接：https://www.zhihu.com/question/7552119044/answer/62194443453\r\n来源：知乎\r\n著作权归作者所有。商业转载请联系作者获得授权，非商业转载请注明出处。',2,0,0,6,1,0,'2025-08-14 11:42:19','2024-12-26 19:40:20','2025-06-27 01:45:29',0),(45,28,84,2,'1.男的是不会要巧克力的，不管什么节日，所以出送巧克力主意的肯定是个女高管，ESG还在发力。2.提高客服工资说明京东已经完全从业务驱动型公司变成了权力驱动型公司，谁离权力中心更近，就能首先获得利益。3.京东完全不在乎网上的评论，毕竟你们叫的再响，我掏出个国补你不还是乖乖掏钱。一群乌合之众而已。\r\n\r\n作者：鹿三\r\n链接：https://www.zhihu.com/question/7886281878/answer/64192859116\r\n来源：知乎\r\n著作权归作者所有。商业转载请联系作者获得授权，非商业转载请注明出处。',2,0,0,0,1,0,'2025-08-14 11:42:19','2024-12-26 19:41:05','2025-06-27 01:45:29',0),(46,28,84,2,'挺心寒的，从几年前各种网盘公司倒闭删数据，到很多笔记公司倒闭丢数据。本想长期使用的各种网络服务却因为各种原因停止，刚用熟悉的工作流没了，自己的数据能不能保住都成了问题。这次停止中国区用户服务还没有以前的案例那么严重，好在git本身是个通用工具，用户至少还可以把自己的代码库迁移走。有足够精力自己搭建git服务器的，可以自己找个服务器来完成新工作流的搭建。我以前就这么做过，还是相当消耗精力的，搭建的服务器也有一堆隐患。比如权限管理的困难，忘记了禁止\"git push -f\"，需要自己费心定期备份服务器数据等等。工作流管理上用Trac，包括wiki和bug tracker，同样是用着很不错，但自己维护起来也着实不算轻松。\r\n\r\n作者：gashero\r\n链接：https://zhuanlan.zhihu.com/p/14785894054\r\n来源：知乎\r\n著作权归作者所有。商业转载请联系作者获得授权，非商业转载请注明出处。',0,0,0,0,1,0,'2025-08-14 11:42:19','2024-12-26 19:41:23','2025-06-27 01:45:29',0),(47,28,84,2,'不想自己搞服务器搭建的朋友，也可以考虑把git仓库迁移到腾讯云CNB(Cloud Native Buildpacks)。相比基础的git服务，也提供了构建流程的友好支持。很多大型软件项目都涉及到复杂项目的构建，构建过程的各种依赖关系错综复杂。以前做自动驾驶业务时，构建过程就需要产出车上几个结点的镜像，安全员操作UI的apk包，离线数据挖掘的CUDA程序等等，常常一次完整构建要运行几个小时。搭建这套流程时infra组也着实干了两个多月，后续还要每周投入一些时间维护新的依赖性。像这些复杂依赖的构建腾讯云CNB就提供了良好的支持。\r\n\r\n作者：gashero\r\n链接：https://zhuanlan.zhihu.com/p/14785894054\r\n来源：知乎\r\n著作权归作者所有。商业转载请联系作者获得授权，非商业转载请注明出处。',1,0,0,3,1,0,'2025-08-14 11:42:19','2024-12-26 19:41:34','2025-06-27 01:45:29',0),(48,28,84,2,'现代很多软件系统的构建基于Docker容器，把软件的所有依赖一股脑都装容器里，简单用一下很简单，但到了构建环节是相当的痛苦。依赖已经复杂到难以理清，只好继续这么用，我就见过一些系统能把镜像搞到几十GB。这对开发测试仿真等都是个巨大的挑战。腾讯云CNB基于COW(Copy On Write)的方式来拉取镜像，使得构建系统像缓存一样，不必重复拉取整个镜像中没改变的部分，可以有效的降低构建的时间提高效率。这一点对于在版本库里使用大量二进制文件的项目也有很大帮助，比如图片，视频，动态库等，对游戏开发就很友好。git最初是为文本源码设计的，但随着应用广泛，各种非文本也纳入版本控制已是现实，COW机制就使得整个集群在clone时都能以缓存方式高效工作。\r\n\r\n作者：gashero\r\n链接：https://zhuanlan.zhihu.com/p/14785894054\r\n来源：知乎\r\n著作权归作者所有。商业转载请联系作者获得授权，非商业转载请注明出处。',2,0,0,15,1,0,'2025-08-14 11:42:19','2024-12-26 19:41:49','2025-06-27 01:45:29',0),(49,28,84,2,'对不熟悉的读者解释一下COW(Copy On Write)机制，我最早学习到该机制是来自于Linux的子进程管理。创建一个子进程时，自动将父进程的所有内存片段都提供给子进程可供读取。这样避免了为子进程做大量的内存复制，提高了效率。只有在子进程修改某个内存片段时，才会将这个内存片段复制到子进程的内存空间，这个过程就是Copy On Write。对Linux进程的内存空间来说，一部分是代码空间，机器学习应用的预测部分的模型是只读的，其他很多应用也往往是父进程读取一次后续只读，对大量的此类内存片段都无需再拷贝。对git版本库也是如此，很多运行稳定的代码和资源是长期无需修改的，腾讯云CNB的COW机制也就帮助提高了效率。一些测试中，在有较多资源是无需修改时，20秒就能完成200G缓存准备，编译百G大仓库也只需要3分钟，这都大幅度缩短了开发验证周期。\r\n\r\n作者：gashero\r\n链接：https://zhuanlan.zhihu.com/p/14785894054\r\n来源：知乎\r\n著作权归作者所有。商业转载请联系作者获得授权，非商业转载请注明出处。',0,1,0,22,1,0,'2025-08-14 11:42:19','2024-12-26 19:42:01','2025-06-27 01:45:29',0),(50,30,84,1,'48,49',0,0,0,0,1,0,'2025-08-14 11:42:19','2025-02-11 19:06:10','2025-06-27 01:45:29',0),(51,31,84,1,'50,51,52',0,0,0,0,1,0,'2025-08-14 11:42:19','2025-02-11 19:06:41','2025-06-27 01:45:29',0),(52,31,84,1,'53,54',0,0,0,0,1,0,'2025-08-14 11:42:19','2025-02-11 19:14:27','2025-06-27 01:45:29',0),(53,31,84,1,'55,56,57,58,59,60',0,0,0,0,1,0,'2025-08-14 11:42:19','2025-02-11 19:15:27','2025-06-27 01:45:29',0),(54,30,84,1,'61,62',0,0,0,0,1,0,'2025-08-14 11:42:19','2025-02-16 22:48:34','2025-06-27 01:45:29',0),(55,30,84,2,'<h2>Hi there,</h2><p>this is a <em>basic</em> example of <strong>Tiptap</strong>. Sure, there are all kind of basic text styles you’d probably expect from a text editor. But wait until you see the lists:</p><ul><li><p>That’s a bullet list with one …</p></li><li><p>… or two list items.</p></li></ul><p>Isn’t that great? And all of that is editable. But wait, there’s more. Let’s try a code block:</p><pre><code class=\"language-css\">body {\n  display: none;\n}</code></pre><p>I know, I know, this is impressive. It’s only the tip of the iceberg though. Give it a try and click a little bit around. Don’t forget to check the other examples too.</p><blockquote><p>Wow, that’s amazing. Good work, boy! ? <br>— Mom</p></blockquote>',0,0,0,0,1,0,'2025-08-14 11:42:19','2025-02-17 00:06:25','2025-06-27 01:45:29',0),(56,30,84,2,'<h2>Hi there,</h2><p>this is a <em>basic</em> example of <strong>Tiptap</strong>. Sure, there are all kind of basic text styles you’d probably expect from a text editor. But wait until you see the lists:</p><ul><li><p>That’s a bullet list with one …</p></li><li><p>… or two list items.</p></li></ul><p>Isn’t that great? And all of that is editable. But wait, there’s more. Let’s try a code block:</p><pre><code class=\"language-css\">body {\n  display: none;\n}</code></pre><p>I know, I know, this is impressive. It’s only the tip of the iceberg though. Give it a try and click a little bit around. Don’t forget to check the other examples too.</p><blockquote><p>Wow, that’s amazing. Good work, boy! ? <br>— Mom</p></blockquote>',0,0,0,0,1,0,'2025-08-14 11:42:19','2025-02-17 00:06:37','2025-06-27 01:45:29',0),(57,30,84,2,'<h2>Hi there,</h2><p>this is a <em>basic</em> example of <strong>Tiptap</strong>. Sure, there are all kind of basic text styles you’d probably expect from a text editor. But wait until you see the lists:</p><ul><li><p>That’s a bullet list with one …</p></li><li><p>… or two list items.</p></li></ul><p>Isn’t that great? And all of that is editable. But wait, there’s more. Let’s try a code block:</p><pre><code class=\"language-java\">class A{\n  int a = 1;\n}</code></pre><pre><code class=\"language-css\">body {\n  display: none;\n}</code></pre><p>I know, I know, this is impressive. It’s only the tip of the iceberg though. Give it a try and click a little bit around. Don’t forget to check the other examples too.</p><blockquote><p>Wow, that’s amazing. Good work, boy! ? <br>— Mom</p></blockquote>',1,0,0,1,1,0,'2025-08-14 11:42:19','2025-02-17 00:17:55','2025-06-27 01:45:29',0),(58,30,84,2,'<h2>Hi there,</h2><table style=\"min-width: 75px\"><colgroup><col style=\"min-width: 25px\"><col style=\"min-width: 25px\"><col style=\"min-width: 25px\"></colgroup><tbody><tr><th colspan=\"1\" rowspan=\"1\"><p><strong>Tiptap</strong></p></th><th colspan=\"1\" rowspan=\"1\"><p><strong>kind</strong></p></th><th colspan=\"1\" rowspan=\"1\"><p><strong>styles</strong></p></th></tr><tr><td colspan=\"1\" rowspan=\"1\"><p>Isn’t that great</p></td><td colspan=\"1\" rowspan=\"1\"><p>a</p></td><td colspan=\"1\" rowspan=\"1\"><p>b</p></td></tr><tr><td colspan=\"1\" rowspan=\"1\"><p>that is editable</p></td><td colspan=\"1\" rowspan=\"1\"><p>a</p></td><td colspan=\"1\" rowspan=\"1\"><p>a</p></td></tr></tbody></table><p></p><p>this is a <em>basic</em> example of <strong>Tiptap</strong>. Sure, there are all kind of basic text styles you’d probably expect